var lazy = $('').lazyRule((lzstr, ty) => {
    var html = request(input, {
        headers: {
            "User-Agent": PC_UA
        }
    });
    eval(JSON.parse(lzstr).rule);
    var scr = html.match(/window\["\\x65\\x76\\x61\\x6c"\](.*?)(?= <\/script>)/)[1];
    var comic = eval(scr);
    var imgdata = JSON.parse(comic.match(/SMH\.imgData\((.*?)\)\.preInit\(\)/)[1]);
    var imgfile = imgdata.files;
    var tim = imgdata.sl.e;
    var path = imgdata.path;
    var mstr = imgdata.sl.m;
    var tup = []
    for (var i in imgfile) {
        tup.push(ty + path + imgfile[i] + '?e=' + tim + '&m=' + mstr + '@Referer=https://www.manhuagui.com/')
    }
    return "pics://" + tup.join("&&")
}, lzstr, ty);

